sys_ui_action.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
// RAJ changes for closing children
if(current.u_reviewer_signed == true)
	closeTask("Approved");
else
	gs.addErrorMessage('You must check the signed checkbox before submitting this task');

function closeTask(DecisionToClose){
	//var dialog = new GlideDialogWindow(""CloseChildrenCheck"");
	//dialog.setTitle(""Cancel All Children?"");
	//dialog.render();

	var blnClose = true;

	if  (current.calchaschildren > 0 &&
		current.progress_of_sub_tasks != 3 &&
	current.progress_of_sub_tasks != 4 &&
	current.progress_of_sub_tasks != 7){

		// TODO - this needs to become a dialog and push language somewhere to be read back
		//blnClose = confirm('TODO this Message needs to be changed into a dialog so users can make a choice and the text is read from a language table.             This Tasker has Sub Tasks that are not closed.  Do you want to ' + current.state + ' this Tasker and all sub taskers?  If yes, theclose note will be pushed to all open subtaskers.');
		blnClose = true;
	}
	if (blnClose){
		// NOTE: the updates happen on the server in a business rule.
		// So, in the client script, we just need to deal with the user cancelling the update
		// reset the assigned members to the previous value on cancel
		current.decision = DecisionToClose;

		// STRY0079666
		var stateClosedFrom = current.state;

		current.state = 3;
		current.active = 'false';
		var gdt = new GlideDateTime();
		current.work_end = gdt.getValue();
		current.work_notes = gs.getMessage('Tasker - This task has been signed by') + current.assigned_to.name;

		current.update();

		// STRY0079666
		var isTaskeOwner = current.u_task_requester == gs.getUserID();
		var isReviewer = current.u_reviewer == gs.getUserID();
		var isAssignedMember = current.assigned_to == gs.getUserID();

		var grResponseLog = new GlideRecordSecure('x_153465_discovert_discover_tasker_response');
		grResponseLog.initialize();
		grResponseLog.u_task_tree = current.u_task_tree;
		grResponseLog.u_task = current.getUniqueValue();
		grResponseLog.u_task_number = current.number;
		grResponseLog.u_responded_by = gs.getUserID();
		grResponseLog.u_role = isReviewer ? 'reviewer' : isTaskeOwner ? 'task_owner' : '';
		grResponseLog.response = current.comments_dt;
		grResponseLog.u_action_taken = 'approve_sign';
		var grOU = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		if (grOU.get(current.primary_assignee)){
			grResponseLog.u_primary_assignee = grOU.getValue('office_abbreviation');
			grResponseLog.u_primary_assignee_office_name = grOU.getValue('office_name');
		}
		grResponseLog.insert();

		gs.addInfoMessage(current.number + gs.getMessage('Tasker - has been successfully') + DecisionToClose + gs.getMessage('Tasker - and marked as Completed'));
	}
	action.setRedirectURL(current);
}
